// 版本一
class Counter {
  count = 0;
  add() { return ++this.count; }
}
const a = new Counter();
const b = new Counter();
a.add(); a.add();
console.log(a.add(), b.add());

// 版本二
function makeCounter() {
  let count = 0;
  return { add: () => ++count };
}
const c = makeCounter();
const d = makeCounter();
c.add(); c.add();
console.log(c.add(), d.add());

